const raw = $json || {};
const orders = Object.entries(raw).map(([id, value]) => ({ ...(value || {}), fbKey: id }));

const start = new Date();
start.setHours(0, 0, 0, 0);
const dayStart = start.getTime();

const todayOrders = orders.filter((order) => Number(order.createdAt || 0) >= dayStart);

const byStatus = { pending: 0, approved: 0, rejected: 0 };
let revenueApproved = 0;

for (const order of todayOrders) {
  const status = String(order.status || 'pending');
  if (status === 'approved') {
    byStatus.approved += 1;
    revenueApproved += Number(order.total || 0);
  } else if (status === 'rejected') {
    byStatus.rejected += 1;
  } else {
    byStatus.pending += 1;
  }
}

const bookSales = {};
for (const order of orders.filter((item) => String(item.status || 'pending') === 'approved')) {
  const items = Array.isArray(order.items) ? order.items : [];
  for (const item of items) {
    const title = item?.title || 'Livre';
    bookSales[title] = (bookSales[title] || 0) + Number(item?.qty || 1);
  }
}

const topBooks = Object.entries(bookSales)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([title, qty], index) => `${index + 1}. ${title} (${qty})`);

const totalToday = todayOrders.length;
const revenueText = revenueApproved.toLocaleString('fr-FR');

const lines = [
  'Rapport quotidien Librairie YO',
  `Date: ${new Date().toLocaleDateString('fr-FR')}`,
  '',
  `Commandes du jour: ${totalToday}`,
  `En attente: ${byStatus.pending}`,
  `Approuvees: ${byStatus.approved}`,
  `Rejetees: ${byStatus.rejected}`,
  `CA approuve (jour): ${revenueText} GNF`,
  '',
  'Top livres (global approuve):',
  ...(topBooks.length ? topBooks : ['Aucune vente approuvee'])
];

return [{ json: { text: lines.join('\n') } }];
